    def time_window_priority(time_to_arrive, window_start, window_end):
        if time_to_arrive <= window_start:
            return window_start - time_to_arrive  # Early arrival, wait needed
        elif time_to_arrive <= window_end:
            return 0  # Within time window, optimal
        else:
            return (time_to_arrive - window_end) * 100  # Late, heavy penalty

    # Initial best choice with high initial cost
    min_cost = float('inf')
    best_node = None

    # Evaluate each unvisited customer
    for idx, customer in enumerate(unvisited_customers):
        t_time = travel_time(cur_truck_pos, customer)
        time_to_arrive = current_time + t_time
        window_start, window_end = time_windows[idx]

        priority_cost = time_window_priority(time_to_arrive, window_start, window_end)
        # Waiting cost based on future availability and needing to wait for the window to open
        wait_cost = max(0, window_start - time_to_arrive) if time_to_arrive < window_start else 0

        # Discourage trucks from flocking to the same targets simultaneously
        coordinate_cost = 0
        for truck_pos in all_truck_pos:
            if not np.array_equal(truck_pos, cur_truck_pos):
                for j, other_customer in enumerate(unvisited_customers):
                    if np.array_equal(other_customer, customer):
                        future_truck_arrival = current_time + travel_time(truck_pos, other_customer)
                        if abs(future_truck_arrival - time_to_arrive) < np.minimum(window_end - time_to_arrive, window_end - future_truck_arrival):
                            coordinate_cost += 50  # Conflict cost

        total_cost = priority_cost + wait_cost + coordinate_cost

        if total_cost < min_cost:
            min_cost = total_cost
            best_node = idx

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    def total_distance_to_depot(customer_pos):
        return euclidean_distance(customer_pos, depot_pos)

    def cost_function(arrival_time, window_start, window_end):
        if arrival_time < window_start:
            return (window_start - arrival_time) * 0.5  # Adjusted waiting cost weight
        elif arrival_time > window_end:
            return (arrival_time - window_end) * 20  # Increased penalty for missing window
        return 0

    def calculate_load_balance_cost(customer_idx):
        current_truck_distance = euclidean_distance(cur_truck_pos, unvisited_customers[customer_idx])
        other_trucks_distances = np.array([euclidean_distance(truck_pos, unvisited_customers[customer_idx]) for truck_pos in all_truck_pos if not np.array_equal(truck_pos, cur_truck_pos)])
        if len(other_trucks_distances) == 0:
            return 0
        return current_truck_distance - np.min(other_trucks_distances)

    best_node = None
    best_total_cost = float('inf')

    for idx, customer in enumerate(unvisited_customers):
        travel_time = euclidean_distance(cur_truck_pos, customer) / truck_speed
        possible_arrival_time = current_time + travel_time
        window_start, window_end = time_windows[idx]

        direct_cost = cost_function(possible_arrival_time, window_start, window_end)
        balance_cost = calculate_load_balance_cost(idx)
        back_to_depot_cost = total_distance_to_depot(customer) * 0.1  # Light cost weight for return distance to depot

        total_cost = direct_cost + balance_cost + back_to_depot_cost

        if total_cost < best_total_cost:
            best_total_cost = total_cost
            best_node = idx

    return best_node
